#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char S[N + 1];
        scanf("%s", S);
        char smallest = S[0];
        int smallestIndex = 0;
        for (int i = 1; i < N; i++) {
            if (S[i] < smallest) {
                smallest = S[i];
                smallestIndex = i;
            }
        }
        for (int i = smallestIndex; i < N - 1; i++) {
            S[i] = S[i + 1];
        }
        S[N - 1] = smallest;
        printf("%s\n", S);
    }
    return 0;
}

