code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String S = sc.next();
            char smallest = S.charAt(0);
            int smallestIndex = 0;
            for (int i = 1; i < N; i++) {
                if (S.charAt(i) < smallest) {
                    smallest = S.charAt(i);
                    smallestIndex = i;
                }
            }
            S = S.substring(0, smallestIndex) + S.substring(smallestIndex + 1, N) + smallest;
            System.out.println(S);
        }
    }
}

